noncompliant:
struct A { int x, y; };
struct B { struct A a; };

struct A a = {.y = 1, .x = 2}; // Noncompliant: out of order (valid C, invalid C++)
int arr[3] = {[1] = 5};        // Noncompliant: array initialization (valid C, invalid C++)
struct B b = {.a.x = 0};       // Noncompliant: nested initialization (valid C, invalid C++)
struct A c = {.x = 1, 2};      // Noncompliant: mixed style (valid C, invalid C++)

compliant:
struct Point {
  float x = 0.0;
  float y = 0.0;
  float z = 0.0;
};

Point p = {
  .x = 1.0,
  .y = 2.0  // Compliant: C++20 designated initializers in order
  // z will be 0.0
};

struct A { int x, y; };
struct A compliant_a = {.x = 1, .y = 2}; // Compliant: in declaration order

// Alternative: traditional initialization
struct A traditional = {1, 2}; // Compliant: positional initialization
